import{_ as e,o as t,c as a,a as o}from"./app.23d84491.js";const m=JSON.parse('{"title":"WackyAki v. Meat312, Dec 2017","description":"","frontmatter":{},"headers":[{"level":2,"title":"Charges","slug":"charges","link":"#charges","children":[]},{"level":2,"title":"Plea","slug":"plea","link":"#plea","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]},{"level":2,"title":"Outcome","slug":"outcome","link":"#outcome","children":[]},{"level":2,"title":"Appeal Outcome","slug":"appeal-outcome","link":"#appeal-outcome","children":[]}],"relativePath":"government/court-cases-precedents/wackyaki_v_meat312_dec_2017.md","lastUpdated":1666028275000}'),i={name:"government/court-cases-precedents/wackyaki_v_meat312_dec_2017.md"},r=o('<h1 id="wackyaki-v-meat312-dec-2017" tabindex="-1">WackyAki v. Meat312, Dec 2017 <a class="header-anchor" href="#wackyaki-v-meat312-dec-2017" aria-hidden="true">#</a></h1><p><strong>Judge</strong>: Klasikrok</p><p><strong>Date</strong>: 2nd December 2017</p><h2 id="charges" tabindex="-1">Charges <a class="header-anchor" href="#charges" aria-hidden="true">#</a></h2><p>Meat312 with corruption and bribery</p><h2 id="plea" tabindex="-1">Plea <a class="header-anchor" href="#plea" aria-hidden="true">#</a></h2><p>Not guilty</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><ul><li><p>Aki proceeds to give a long ass speech about how political corruption and bribery for votes corrupts the nation.</p></li><li><p>meat counters and declares that there is no law against vote buying.</p></li><li><p>Aki continues to say that vote buying corrupts things.</p></li></ul><h2 id="outcome" tabindex="-1">Outcome <a class="header-anchor" href="#outcome" aria-hidden="true">#</a></h2><p>Meat found not guilty for lack of laws against bribery. Aki appeals the decision with petition support from Feathercrown and Amerikkalainen</p><h2 id="appeal-outcome" tabindex="-1">Appeal Outcome <a class="header-anchor" href="#appeal-outcome" aria-hidden="true">#</a></h2><blockquote><p>Alright, so I&#39;ve reviewed the evidence. WackyAki, I believe that you have gone far enough in this matter. Any further harassment of meat on this issue will be considered actual harassment. However, there is a core issue here which is whether vote-buying is a legitimate expression. I believe that it is not.</p></blockquote><blockquote><p>Councillors should stand by the merits of their ideas, not the contents of their purse. The purpose of the council is to represent the will of the population of Yoahtl in the form of the ideas held by those they elect to represent them. Allowing councillors to buy their way onto the council totally subverts this. In short, councillors who get onto the council via vote buying are violating the purpose of the chamber. meat has a right to do what he wishes, but if he wishes to enter into an institution that institution may set standards of behavior to which he must ascede.</p></blockquote><blockquote><p>Buying people&#39;s votes is not a legitimate form of political campaigning or of expression. I will leave the council to decide what precisely counts as &quot;buying&quot; a vote.</p></blockquote><p>-bgbba</p>',16),s=[r];function n(c,l,h,d,p,u){return t(),a("div",null,s)}const _=e(i,[["render",n]]);export{m as __pageData,_ as default};
